// /frontend/src/components/BottomBar.jsx  (unchanged)
import React from "react";

export default function BottomBar({ active = "now", onNav }) {
  const Item = ({ id, label, icon }) => (
    <button
      onClick={() => onNav?.(id)}
      className={`flex flex-col items-center gap-1 px-3 py-1 rounded-xl ${
        active === id ? "opacity-100" : "opacity-70"
      } hover:opacity-100`}
      aria-current={active === id ? "page" : undefined}
    >
      <span aria-hidden>{icon}</span>
      <span className="text-xs">{label}</span>
    </button>
  );

  return (
    <nav className="fixed bottom-0 left-0 right-0 z-40">
      <div className="mx-auto max-w-3xl px-4 pb-5">
        <div className="rounded-2xl backdrop-blur-xl bg-black/40 ring-1 ring-white/10 px-6 py-3 flex justify-around">
          <Item id="now" label="Now" icon="🏠" />
          <Item id="chatbot" label="Chatbot" icon="💬" />
          <Item id="community" label="Community" icon="🌐" />
        </div>
      </div>
    </nav>
  );
}
